# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'BUILD_COMMAND', defaultValue: '', description: 'Enter the build command')
        string(name: 'TEST_COMMAND', defaultValue: '', description: 'Enter the test script')
        string(name: 'DEPLOY_COMMAND', defaultValue: '', description: 'Enter the deployment step')
    }

    stages {
        stage('Build') {
            steps {
                echo "Executing build command: ${params.BUILD_COMMAND}"
                sh "${params.BUILD_COMMAND}"
            }
        }

        stage('Test') {
            steps {
                echo "Executing test script: ${params.TEST_COMMAND}"
                sh "${params.TEST_COMMAND}"
            }
        }

        stage('Deploy') {
            steps {
                echo "Executing deployment step: ${params.DEPLOY_COMMAND}"
                sh "${params.DEPLOY_COMMAND}"
            }
        }
    }
}